#!/usr/bin/env python3
import rclpy
from rclpy.node import Node
from sensor_msgs.msg import LaserScan
from geometry_msgs.msg import Twist
import math

class SafetyStopNode(Node):
    def __init__(self):
        super().__init__('safety_stop_node')

        # 파라미터
        self.declare_parameter('stop_distance', 0.5)
        self.declare_parameter('front_angle_range', 5.0)
        self.declare_parameter('slowdown_distance', 0.8)

        self.stop_distance = float(self.get_parameter('stop_distance').value or 0.5)
        self.front_angle_range = float(self.get_parameter('front_angle_range').value or 5.0)
        self.slowdown_distance = float(self.get_parameter('slowdown_distance').value or 0.8)

        # 입력: collision_monitor 출력 (자율주행 명령)
        self.nav_cmd_sub = self.create_subscription(
            Twist, '/cmd_vel_nav', self.cmd_vel_callback, 10)

        # LiDAR 스캔 구독
        self.scan_sub = self.create_subscription(
            LaserScan, '/scan', self.scan_callback, 10)

        # 출력: mode_switch_node로 전달
        self.cmd_pub = self.create_publisher(Twist, '/cmd_vel_safe', 10)

        self.front_distance = float('inf')
        self.is_stopped = False

        self.get_logger().info(
            f'Safety Stop Node 시작\n'
            f'  입력: /cmd_vel_nav → 출력: /cmd_vel_safe\n'
            f'  정지거리: {self.stop_distance}m\n'
            f'  감속거리: {self.slowdown_distance}m\n'
            f'  정면 범위: ±{self.front_angle_range}도')

    def scan_callback(self, msg):
        """LiDAR 스캔에서 정면(0도) 부근 최소 거리 추출"""
        angle_min = msg.angle_min
        angle_increment = msg.angle_increment
        ranges = msg.ranges

        front_range_rad = math.radians(self.front_angle_range)
        min_distance = float('inf')

        for i, r in enumerate(ranges):
            if r < msg.range_min or r > msg.range_max:
                continue
            angle = angle_min + i * angle_increment
            if abs(angle) <= front_range_rad:
                if r < min_distance:
                    min_distance = r

        self.front_distance = min_distance

    def cmd_vel_callback(self, msg):
        """자율주행 명령을 안전 필터링 후 발행"""
        safe_cmd = Twist()

        if self.front_distance <= self.stop_distance:
            if msg.linear.x > 0:
                safe_cmd.linear.x = 0.0
                safe_cmd.angular.z = msg.angular.z
                if not self.is_stopped:
                    self.get_logger().warn(
                        f'긴급 정지! 정면 장애물 거리: {self.front_distance:.2f}m')
                    self.is_stopped = True
            else:
                safe_cmd = msg
                self.is_stopped = False

        elif self.front_distance <= self.slowdown_distance:
            ratio = (self.front_distance - self.stop_distance) / \
                    (self.slowdown_distance - self.stop_distance)
            if msg.linear.x > 0:
                safe_cmd.linear.x = msg.linear.x * ratio
                safe_cmd.angular.z = msg.angular.z
                self.get_logger().info(
                    f'감속 중 - 거리: {self.front_distance:.2f}m, '
                    f'속도 비율: {ratio:.1%}')
            else:
                safe_cmd = msg
            self.is_stopped = False

        else:
            safe_cmd = msg
            self.is_stopped = False

        self.cmd_pub.publish(safe_cmd)


def main(args=None):
    rclpy.init(args=args)
    node = SafetyStopNode()
    rclpy.spin(node)
    node.destroy_node()
    rclpy.shutdown()

if __name__ == '__main__':
    main()